using AzureMcp.Areas.Storage.Options.DataLake.FileSystem;
using AzureMcp.Areas.Storage.Services;
using AzureMcp.Commands.Storage;
using AzureMcp.Models.Option;
using AzureMcp.Services.Telemetry;
using Microsoft.Extensions.Logging;

namespace AzureMcp.Areas.Storage.Commands.DataLake.FileSystem;

public sealed class ListPathsCommand(ILogger<ListPathsCommand> logger) : BaseStorageCommand<ListPathsOptions>
{
    private const string CommandTitle = "List Data Lake File System Paths";
    private readonly ILogger<ListPathsCommand> _logger = logger;

    private readonly Option<string> _fileSystemOption = StorageOptionDefinitions.FileSystem;
    private readonly Option<string> _pathOption = StorageOptionDefinitions.Path;
    private readonly Option<bool> _recursiveOption = StorageOptionDefinitions.Recursive;
    private readonly Option<int> _maxResultsOption = StorageOptionDefinitions.MaxResults;

    public override string Name => "list-paths";

    public override string Description =>
        """
        List paths in an Azure Data Lake Storage Gen2 file system. This command retrieves and displays all paths
        (files and directories) available in the specified Data Lake file system. Results include path names
        returned as a JSON array. Requires the storage account name and file system name.
        """;

    public override string Title => CommandTitle;

    protected override void RegisterOptions(Command command)
    {
        base.RegisterOptions(command);
        command.AddOption(_fileSystemOption);
        command.AddOption(_pathOption);
        command.AddOption(_recursiveOption);
        command.AddOption(_maxResultsOption);
    }

    protected override ListPathsOptions BindOptions(ParseResult parseResult)
    {
        var options = base.BindOptions(parseResult);
        options.FileSystem = parseResult.GetValueForOption(_fileSystemOption);
        options.Path = parseResult.GetValueForOption(_pathOption);
        options.Recursive = parseResult.GetValueForOption(_recursiveOption);
        options.MaxResults = parseResult.GetValueForOption(_maxResultsOption);
        return options;
    }

    [McpServerTool(Destructive = false, ReadOnly = true, Title = CommandTitle)]
    public override async Task<CommandResponse> ExecuteAsync(CommandContext context, ParseResult parseResult)
    {
        var options = BindOptions(parseResult);

        try
        {
            if (!Validate(parseResult.CommandResult, context.Response).IsValid)
            {
                return context.Response;
            }

            context.Activity?.WithSubscriptionTag(options);

            var storageService = context.GetService<IStorageService>();
            var paths = await storageService.ListDataLakePaths(
                options.Account!,
                options.FileSystem!,
                options.Path,
                options.Recursive,
                options.MaxResults,
                options.Subscription,
                options.Tenant,
                options.RetryPolicy);

            context.Response.Results = paths?.Count > 0
                ? ResponseResult.Create(new ListPathsCommandResult(paths), StorageJsonContext.Default.ListPathsCommandResult)
                : null;
        }
        catch (Exception ex)
        {
            _logger.LogError(ex,
                "Error listing Data Lake paths. Account: {Account}, FileSystem: {FileSystem}, Path: {Path}.",
                options.Account, options.FileSystem, options.Path);
            HandleException(context.Response, ex);
        }

        return context.Response;
    }

    internal record ListPathsCommandResult(List<string> Paths);
}

